import math

def kepler_to_cartesian(a, e, i, omega, w, nu):
    """
    Calculate Keplerian elements to Cartesian coordinates.

    Parameters:
    a (float): Semi-major axis in km
    e (float): Eccentricity
    i (float): Inclination in radians
    omega (float): Right ascending node in radians
    w (float): Argument of periapsis in radians
    nu (float): Mean anomaly in radians

    Returns:
    tuple: x, y, z in km
    """
